# Building your own mini-benchmark
from dataclasses import dataclass

@dataclass
class EvalSample:
    question: str
    expected_answer: str
    rubric: str  # how to evaluate the model's response

class MiniBenchmark:
    def __init__(self):
        self.samples: list[EvalSample] = []
        self.metrics = {"exact_match": 0, "partial": 0, "wrong": 0}

    def add_sample(self, question: str, answer: str, rubric: str = "exact"):
        self.samples.append(EvalSample(question, answer, rubric))

    def evaluate(self, model_fn) -> dict:
        """model_fn: takes a question string, returns an answer string"""
        self.metrics = {"exact_match": 0, "partial": 0, "wrong": 0}
        for s in self.samples:
            response = model_fn(s.question)
            if s.rubric == "exact":
                if response.strip().lower() == s.expected_answer.strip().lower():
                    self.metrics["exact_match"] += 1
                else:
                    self.metrics["wrong"] += 1
            elif s.rubric == "contains":
                if s.expected_answer.lower() in response.lower():
                    self.metrics["partial"] += 1
                else:
                    self.metrics["wrong"] += 1
        total = len(self.samples)
        return {k: v / total for k, v in self.metrics.items()}

# Usage
bench = MiniBenchmark()
bench.add_sample("What is 2+2?", "4", "exact")
bench.add_sample("Name a color in the rainbow.", "red", "contains")
results = bench.evaluate(lambda q: my_model.generate(q))
print(f"Accuracy: {results['exact_match']:.0%}")

# LLM-as-Judge — pairwise comparison

JUDGE_PROMPT = """You are evaluating two AI assistants' responses.

[User Question]
{question}

[Assistant A]
{response_a}

[Assistant B]
{response_b}

Evaluate which response is more helpful, accurate, and safe.
First explain your reasoning, then output your verdict on the last line:
"[[A]]" if A is better, "[[B]]" if B is better, or "[[TIE]]" if equal."""

def pairwise_judge(question: str, response_a: str, response_b: str, judge_model) -> str:
    prompt = JUDGE_PROMPT.format(
        question=question, response_a=response_a, response_b=response_b
    )
    result = judge_model.generate(prompt)
    # Extract verdict from last line
    for line in reversed(result.split("\n")):
        line = line.strip()
        if line in ("[[A]]", "[[B]]", "[[TIE]]"):
            return line
    return "[[TIE]]"  # default if parsing fails

# Mitigate position bias: run twice with swapped order
def robust_pairwise_judge(q, a, b, judge) -> str:
    r1 = pairwise_judge(q, a, b, judge)
    r2 = pairwise_judge(q, b, a, judge)
    # Map swapped results back
    r2_map = {"[[A]]": "[[B]]", "[[B]]": "[[A]]", "[[TIE]]": "[[TIE]]"}
    if r1 == r2_map.get(r2, "[[TIE]]"):
        return r1  # consistent
    return "[[TIE]]"  # inconsistent

