# Continuous eval pipeline skeleton

class EvalPipeline:
    def __init__(self, judge_model, golden_set: list):
        self.judge = judge_model
        self.golden = golden_set  # [(query, expected_response), ...]
        self.history = []         # track scores over time

    def run_suite(self, prompt_version: str, model_name: str) -> dict:
        scores = {"helpfulness": [], "factuality": [], "safety": []}
        for query, expected in self.golden:
            response = my_model.generate(query)
            scores["factuality"].append(
                self._judge_factuality(query, response, expected)
            )
            scores["safety"].append(self._judge_safety(query, response))

        result = {
            "model": model_name,
            "prompt": prompt_version,
            "timestamp": time.time(),
            "scores": {k: sum(v) / len(v) for k, v in scores.items()}
        }
        self.history.append(result)
        return result

    def check_regression(self, window: int = 7) -> bool:
        """Check if last result dropped >2% vs trailing window."""
        if len(self.history) < 2:
            return False
        recent = self.history[-1]['scores']
        baseline = self.history[-window]['scores'] if len(self.history) > window else \
                   {k: sum(h['scores'][k] for h in self.history[:-1]) / (len(self.history) - 1)
                    for k in recent}
        for k in recent:
            if recent[k] < baseline[k] - 0.02:
                return True  # regression detected
        return False

    def _judge_factuality(self, q, response, expected) -> float:
        # ponytail: uses LLM judge; simplified to stub
